# 021-quasi_geo-events.R
# Generated by behavior-preserving split of quasi_geo_test.R.

qgt_event_scan_one <- function(dt,
                               date_col,
                               geo_col,
                               variable,
                               media_col,
                               pre_weeks,
                               post_weeks,
                               min_abs_change,
                               min_pct_change,
                               min_robust_z,
                               min_volume,
                               media_cutoff_pct,
                               rolling_window,
                               period_days = 7L) {
  d <- copy(dt)
  period_days <- as.integer(period_days)[1]
  if (!is.finite(period_days) || period_days <= 0L) stop("period_days must be a positive integer.")
  setorderv(d, c(geo_col, date_col))
  d[, x__ := pmax(qgt_num(get(media_col)), 0)]
  primary_materiality <- max(min_volume, 0.05 * qgt_positive_scale(d$x__, floor = min_volume))
  primary_near_zero <- max(1e-8, min_volume * media_cutoff_pct)
  effective_min_abs_change <- max(min_abs_change, primary_materiality)
  d[, pre_mean__ := frollmean(shift(x__, 1L), n = rolling_window, align = "right", na.rm = TRUE), by = geo_col]
  d[, pre_med__ := frollapply(shift(x__, 1L), N = rolling_window, FUN = stats::median, align = "right", na.rm = TRUE), by = geo_col]
  d[, pre_mad__ := frollapply(shift(x__, 1L), N = rolling_window, FUN = stats::mad, align = "right", na.rm = TRUE), by = geo_col]
  d[, post_mean__ := frollmean(x__, n = post_weeks, align = "left", na.rm = TRUE), by = geo_col]
  d[, post_min__ := frollapply(x__, N = post_weeks, FUN = function(z) if (all(is.na(z))) NA_real_ else min(z, na.rm = TRUE), align = "left"), by = geo_col]
  d[, post_max__ := frollapply(x__, N = post_weeks, FUN = function(z) if (all(is.na(z))) NA_real_ else max(z, na.rm = TRUE), align = "left"), by = geo_col]
  d[, signed_change__ := post_mean__ - pre_mean__]
  d[, change_abs__ := abs(signed_change__)]
  d[, pct_change__ := fifelse(is.finite(pre_mean__) & pre_mean__ > 1e-8, signed_change__ / pre_mean__, NA_real_)]
  d[, pct_change_abs__ := abs(pct_change__)]
  d[, robust_z__ := fifelse(is.finite(pre_mad__) & pre_mad__ > 1e-8, (post_mean__ - pre_med__) / pre_mad__, NA_real_)]
  d[, robust_z_abs__ := abs(robust_z__)]
  d[, turn_on_flag__ := is.finite(pre_mean__) & pre_mean__ <= primary_near_zero &
      is.finite(post_mean__) & post_mean__ >= primary_materiality &
      change_abs__ >= effective_min_abs_change]
  d[, turn_off_flag__ := is.finite(pre_mean__) & pre_mean__ >= primary_materiality &
      is.finite(post_mean__) & post_mean__ <= primary_near_zero &
      change_abs__ >= effective_min_abs_change]
  d[, post_pos_hit__ := is.finite(pre_mean__) & pre_mean__ > 1e-8 &
      is.finite(post_max__) & ((post_max__ - pre_mean__) / pre_mean__) >= min_pct_change]
  d[, post_neg_hit__ := is.finite(pre_mean__) & pre_mean__ > 1e-8 &
      is.finite(post_min__) & ((post_min__ - pre_mean__) / pre_mean__) <= -min_pct_change]
  d[, media_cutoff_flag__ := is.finite(pre_mean__) & pre_mean__ >= primary_materiality &
      is.finite(post_mean__) & post_mean__ <= pmax(min_volume, pre_mean__ * media_cutoff_pct)]
  d[, ramp_direction__ := data.table::fcase(
    turn_on_flag__, "up_ramp",
    turn_off_flag__, "down_ramp",
    post_pos_hit__ & post_neg_hit__, "mixed",
    signed_change__ > 0, "up_ramp",
    signed_change__ < 0, "down_ramp",
    default = "none"
  )]
  d[, event_type__ := data.table::fcase(
    turn_on_flag__, "turn_on",
    turn_off_flag__ | media_cutoff_flag__, "turn_off",
    default = ramp_direction__
  )]
  d[, event_flag__ := is.finite(signed_change__) &
      pmax(pre_mean__, post_mean__, na.rm = TRUE) >= primary_materiality &
      (
        turn_on_flag__ |
          turn_off_flag__ |
          media_cutoff_flag__ |
          (
            change_abs__ >= effective_min_abs_change &
              ((is.finite(pct_change_abs__) & pct_change_abs__ >= min_pct_change) | turn_on_flag__ | turn_off_flag__) &
              (is.na(robust_z_abs__) | robust_z_abs__ >= min_robust_z)
          )
      )]
  ev <- d[event_flag__ == TRUE, .(
    variable = variable,
    geo = get(geo_col),
    event_start = get(date_col),
    event_end = get(date_col) + period_days * (post_weeks - 1L),
    pre_start = get(date_col) - period_days * pre_weeks,
    pre_end = get(date_col) - period_days,
    post_start = get(date_col),
    post_end = get(date_col) + period_days * (post_weeks - 1L),
    starting_support = pre_mean__,
    event_media = post_mean__,
    signed_treatment_intensity = signed_change__,
    abs_change = change_abs__,
    change_abs = change_abs__,
    pct_change = pct_change__,
    pct_change_abs = pct_change_abs__,
    robust_z = robust_z__,
    ramp_direction = ramp_direction__,
    event_type = event_type__,
    media_cutoff_flag = media_cutoff_flag__
  )]
  ev[, event_id := paste(variable, geo, event_start, ramp_direction, sep = "__")]
  ev[]
}
qgt_empty_candidate_events <- function() {
  data.table(
    variable = character(),
    geo = character(),
    event_start = as.Date(character()),
    event_end = as.Date(character()),
    pre_start = as.Date(character()),
    pre_end = as.Date(character()),
    post_start = as.Date(character()),
    post_end = as.Date(character()),
    starting_support = numeric(),
    event_media = numeric(),
    signed_treatment_intensity = numeric(),
    abs_change = numeric(),
    change_abs = numeric(),
    pct_change = numeric(),
    pct_change_abs = numeric(),
    robust_z = numeric(),
    ramp_direction = character(),
    event_type = character(),
    media_cutoff_flag = logical(),
    event_id = character()
  )
}
qgt_event_not_estimable <- function(event,
                                    reason,
                                    method = "not_estimable") {
  e <- event[1]
  data.table(
    event_id = e$event_id,
    variable = e$variable,
    geo = as.character(e$geo),
    event_start = e$event_start,
    event_end = e$event_end,
    starting_support = e$starting_support,
    event_media = qgt_event_value(e, "event_media", NA_real_),
    signed_treatment_intensity = qgt_event_value(e, "signed_treatment_intensity", qgt_event_value(e, "abs_change", NA_real_)),
    abs_change = qgt_event_value(e, "abs_change", abs(qgt_event_value(e, "signed_treatment_intensity", NA_real_))),
    change_abs = qgt_event_value(e, "change_abs", qgt_event_value(e, "abs_change", NA_real_)),
    pct_change = e$pct_change,
    pct_change_abs = qgt_event_value(e, "pct_change_abs", abs(e$pct_change)),
    robust_z = e$robust_z,
    ramp_direction = qgt_event_value(e, "ramp_direction", qgt_direction_from_signed_change(qgt_event_value(e, "signed_treatment_intensity", NA_real_))),
    event_type = qgt_event_value(e, "event_type", qgt_direction_from_signed_change(qgt_event_value(e, "signed_treatment_intensity", NA_real_))),
    media_cutoff_flag = qgt_event_value(e, "media_cutoff_flag", FALSE),
    donor_n = 0L,
    donor_weight_max = NA_real_,
    donor_weight_hhi = NA_real_,
    donor_effective_n = NA_real_,
    donor_dominant_flag = NA,
    scaled_l2_imbalance = NA_real_,
    pre_fit_score = NA_real_,
    recent_pre_fit_score = NA_real_,
    lookback_sensitivity_score = NA_real_,
    contamination_score = NA_real_,
    signal_score = NA_real_,
    direction_consistency_score = NA_real_,
    power_score = NA_real_,
    evidence_score = 0,
    quality_score = 0,
    evidence_tier = "not_estimable",
    diagnostic_reason = reason,
    placebo_lift = NA_real_,
    placebo_lift_abs_ratio = NA_real_,
    donor_placebo_p_value = NA_real_,
    donor_placebo_strength = NA_real_,
