qgt_empty_event_estimates <- function() {
  template <- data.table(
    event_id = "",
    variable = "",
    geo = "",
    event_start = as.Date("1970-01-01"),
    event_end = as.Date("1970-01-01"),
    starting_support = NA_real_,
    event_media = NA_real_,
    signed_treatment_intensity = NA_real_,
    abs_change = NA_real_,
    change_abs = NA_real_,
    pct_change = NA_real_,
    pct_change_abs = NA_real_,
    robust_z = NA_real_,
    ramp_direction = "none",
    event_type = "none",
    media_cutoff_flag = FALSE
  )
  qgt_event_not_estimable(template, reason = "no_candidate_events")[0]
}
